const client = $('Split Clients').item.json;
const tasks = $input.first().json || [];
const done = tasks.filter(t => t.done).map(t => t.title);
const open = tasks.filter(t => !t.done).map(t => `${t.title} (due ${t.due_date || 'n/a'})`);

const prompt = `You are Clio, the client fulfillment agent for InboundOS. Write this client's weekly report for the founder (Micko) PLUS a short warm client-facing update message Micko can send as-is.

CLIENT: ${client.name} (${client.company || ''}) — ${client.niche || ''}
Phase: ${client.phase} | MRR: $${client.mrr} | Client since: ${client.client_since}
Metrics: posts_delivered=${client.posts_delivered}, reels=${client.reels_posted}, follower_growth=${client.follower_growth_pct}%, engagement=${client.avg_engagement_rate}%
Current next action: ${client.next_action || 'none set'}

COMPLETED TASKS:
${done.length ? done.map(t => '- ' + t).join('\n') : '- (none marked done)'}

OPEN / UPCOMING TASKS:
${open.length ? open.map(t => '- ' + t).join('\n') : '- (none)'}

Return ONLY valid JSON, no markdown, this exact shape:
{
  \"internal_report\": {
    \"delivered\": [\"<what got delivered this week>\"],
    \"overdue\": [\"<anything slipping>\"],
    \"risk\": \"healthy|watch|at_risk\",
    \"next_action\": \"<single most important action for Micko this week>\",
    \"summary\": \"<2 sentence status for Micko, terse>\"
  },
  \"client_update\": \"<warm, simple, no-jargon message Micko can send the client as-is. 3-5 sentences. Mention a real win and the plan for this week.>\"
}`;

return [{ json: { prompt, clientId: client.id, clientName: client.name } }];

const raw = $input.first().json.output || $input.first().json.stdout || '';
const clientId = $('Build Prompt').item.json.clientId;
const clientName = $('Build Prompt').item.json.clientName;
let parsed;
try {
  const clean = raw.replace(/```json?/gi, '').replace(/```/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { internal_report: { summary: 'parse error', risk: 'watch', next_action: '', delivered: [], overdue: [] }, client_update: '' };
}
const r = parsed.internal_report || {};
return [{ json: { clientId, clientName, report: parsed, next_action: r.next_action || '', summary: r.summary || '', client_update: parsed.client_update || '' } }];
